class Solution: def solve(self, nums: list[int]) -> bool: for i in range(len(nums) - 1): minIndex = i for j in range(i + 1, len(nums)): if nums[j] < nums[minIndex]: minIndex = j nums[i], nums[minIndex] = nums[minIndex], nums[i] return self.isSorted(nums)

def isSorted(self, nums: list[int]) -> bool: for i in range(len(nums) - 1): if nums[i] > nums[i + 1]: return False return True

def main(): nums = list(map(int, input().split())) solution = Solution() print(solution.solve(nums))
